const int g_numDarkThemes = sizeof(g_DarkThemes) / sizeof(Theme);
const int g_numLightThemes = sizeof(g_LightThemes) / sizeof(Theme);

int g_currentThemeIndex = 0;
BOOL g_isCurrentThemeDark = TRUE;

DarkMode_ColorsView MakeDarkModeView(DarkMode_Colors* c)
{
    DarkMode_ColorsView v;

    // List background = dialog/control background (neutral dark)
    v.background = c->ctrlBackground;

    // Normal text
    v.text = c->text;

    // Gridlines = faint edge color
    v.gridlines = c->edge;

    // Header background = slightly different from main background for contrast
    v.headerBackground = c->background;

    // Header hot background = use hotBackground for hover effect
    v.headerHotBackground = c->hotBackground;

    // Header text = same as normal text, maybe darkerText if you want subtle
    v.headerText = c->text;

    // Header edge = stronger border (use hotEdge if hover, edge otherwise)
    v.headerEdge = c->edge;

    return v;
}

void ApplyTheme(HWND hwnd, int themeIndex, BOOL isDark) {
    if ((isDark && themeIndex >= g_numDarkThemes) || (!isDark && themeIndex >= g_numLightThemes)) {
        return;
    }

    Theme* selectedTheme = isDark ? &g_DarkThemes[themeIndex] : &g_LightThemes[themeIndex];

    g_currentThemeIndex = themeIndex;
    g_isCurrentThemeDark = isDark;

    // --- Apply Theming using the Library API ---
    DarkMode_DarkModeType mode = selectedTheme->isLight ? DarkMode_DarkModeType_light : DarkMode_DarkModeType_dark;
    DarkMode_setDarkModeConfig(mode);
    DarkMode_setThemeColors(selectedTheme->colors);
    DarkMode_setViewColors(MakeDarkModeView(&selectedTheme->colors));
    ChangeSidebarTheme(selectedTheme->colors);
    DarkMode_updateThemeBrushesAndPens();
    DarkMode_setDarkWndNotifySafeEx(hwnd, TRUE, TRUE);
    DarkMode_setWindowEraseBgSubclass(hwnd);
    RedrawWindow(hwnd, NULL, NULL, RDW_ERASE | RDW_INVALIDATE | RDW_ALLCHILDREN | RDW_FRAME);
}